1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	type Customer = { yearsWithMHPCO: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Scenario = { customer: Customer; steps: QuoteStep[] };
7	type StepResult = { premium: number };
8	type ScenarioResult = { results: StepResult[] };
9	
10	const BASE_PRICES: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
20	
21	const CURSED_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	
25	const isCursed = (item: Item): boolean => item.cursed === true;
26	const isHighlyEnchanted = (item: Item): boolean =>
27	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
28	
29	const surchargeRate = (item: Item): number =>
30	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
31	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
32	
33	const itemPremium = (item: Item): number => {
34	  const base = basePriceOf(item);
35	  return base + base * surchargeRate(item);
36	};
37	
38	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
39	const BLOCK_SIZE = 3;
40	const BLOCK_PRICE = 60;
41	
42	const groupByType = (items: Item[]): Map<string, Item[]> => {
43	  const groups = new Map<string, Item[]>();
44	  for (const item of items) {
45	    const existing = groups.get(item.type) ?? [];
46	    existing.push(item);
47	    groups.set(item.type, existing);
48	  }
49	  return groups;
50	};
51	
52	const groupPremium = (type: string, members: Item[]): number => {
53	  if (COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE) return BLOCK_PRICE;
54	  return members.reduce((sum, item) => sum + itemPremium(item), 0);
55	};
56	
57	const itemsSubtotal = (items: Item[]): number =>
58	  Array.from(groupByType(items)).reduce(
59	    (total, [type, members]) => total + groupPremium(type, members),
60	    0,
61	  );
62	
63	const LOYALTY_DISCOUNT_RATE = 0.2;
64	const LOYALTY_YEARS_THRESHOLD = 2;
65	
66	const isLoyalCustomer = (customer: Customer): boolean =>
67	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
68	
69	const loyaltyDiscountRate = (customer: Customer): number =>
70	  isLoyalCustomer(customer) ? LOYALTY_DISCOUNT_RATE : 0;
71	
72	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
73	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
74	
75	const followUpDiscountRate = (stepIndex: number): number =>
76	  stepIndex > 0 ? FOLLOW_UP_DISCOUNT_RATE : 0;
77	
78	const policyAdjustmentRate = (customer: Customer, stepIndex: number): number =>
79	  FIRST_INSURANCE_SURCHARGE_RATE -
80	  loyaltyDiscountRate(customer) -
81	  followUpDiscountRate(stepIndex);
82	
83	const quotePremium = (
84	  items: Item[],
85	  customer: Customer,
86	  stepIndex: number,
87	): number => {
88	  const subtotal = itemsSubtotal(items);
89	  return (
90	    subtotal +
91	    subtotal * policyAdjustmentRate(customer, stepIndex) +
92	    PROCESSING_FEE
93	  );
94	};
95	
96	const runStep = (
97	  step: QuoteStep,
98	  customer: Customer,
99	  stepIndex: number,
100	): StepResult => ({
101	  premium: quotePremium(step.items, customer, stepIndex),
102	});
103	
104	export const runScenario = (input: Scenario): ScenarioResult => ({
105	  results: input.steps.map((step, i) => runStep(step, input.customer, i)),
106	});
